let status = msg.payload;
if (typeof status === 'string') {
  try { status = JSON.parse(status).status; } catch (e) { /* plain string */ }
} else if (status && typeof status === 'object') {
  status = status.status;
}
const isOnline = status === 'online';
msg.headers = {
  'Content-Type': 'application/json',
  Prefer: 'resolution=merge-duplicates',
  apikey: env.get('SERVICE_ROLE_KEY'),
  Authorization: 'Bearer ' + env.get('SERVICE_ROLE_KEY'),
};
msg.method = 'POST';
msg.url = env.get('SUPABASE_REST') + '/devices?on_conflict=device_id';
msg.payload = [{
  device_id: deviceId,
  name: deviceId,
  is_online: isOnline,
  last_seen: new Date().toISOString(),
}];
return msg;

const deviceId = msg.topic.split('/')[1];
let data = msg.payload;
if (typeof data === 'string') {
  try { data = JSON.parse(data); } catch (e) { data = { value: data }; }
}
if (typeof data !== 'object' || data === null) {
  data = { value: data };
}
const headers = {
  'Content-Type': 'application/json',
  apikey: env.get('SERVICE_ROLE_KEY'),
  Authorization: 'Bearer ' + env.get('SERVICE_ROLE_KEY'),
};
const now = new Date().toISOString();
const telem = {
  headers,
  method: 'POST',
  url: env.get('SUPABASE_REST') + '/telemetry',
  payload: [{ device_id: deviceId, topic: msg.topic, payload: data }],
};
const touch = {
  headers: { ...headers, Prefer: 'resolution=merge-duplicates' },
  method: 'POST',
  url: env.get('SUPABASE_REST') + '/devices?on_conflict=device_id',
  payload: [{ device_id: deviceId, name: deviceId, is_online: true, last_seen: now }],
};
return [telem, touch];
